import { Link } from "react-router-dom";

export default function DriverSidebar() {
  return (
    <aside className="sidebar">
      <div className="brand">SecureRide</div>
      <nav className="nav">
        <Link to="/driver/dashboard">Dashboard</Link>
        <Link to="/driver/trips">Trips</Link>
        <Link to="/driver/emergency-contacts">Emergency Contacts</Link>
      </nav>
    </aside>
  );
}
